package org.eclipse.rdf4j.query.algebra.evaluation.sketch.omni;

import java.nio.charset.StandardCharsets;

import org.apache.datasketches.hash.MurmurHash3;

/** Package-private deterministic hashing utilities for OmniSketch. */
final class OmniSketchHash {
	private static final long NULL_TOKEN = 0x6A09E667F3BCC909L;
	private static final long EMPTY_BYTES_TOKEN = 0xBB67AE8584CAA73BL;
	private static final long IDENTIFIER_SEED_XOR = 0xD1B54A32D192ED03L;
	private static final long ROW_SEED_XOR = 0x9E3779B97F4A7C15L;

	private OmniSketchHash() {
	}

	static long hashValue(final Object value, final long seed) {
		if (value == null) {
			return hashLong(NULL_TOKEN, seed);
		}
		if (value instanceof Long) {
			return hashLong((Long) value, seed);
		}
		if (value instanceof Integer) {
			return hashLong(((Integer) value).longValue(), seed);
		}
		if (value instanceof Short) {
			return hashLong(((Short) value).longValue(), seed);
		}
		if (value instanceof Byte) {
			return hashLong(((Byte) value).longValue(), seed);
		}
		if (value instanceof Boolean) {
			return hashLong((Boolean) value ? 1L : 0L, seed);
		}
		if (value instanceof Double) {
			return hashDouble((Double) value, seed);
		}
		if (value instanceof Float) {
			return hashLong(Float.floatToIntBits((Float) value), seed);
		}
		if (value instanceof Character) {
			return hashLong(((Character) value).charValue(), seed);
		}
		if (value instanceof byte[]) {
			return hashBytes((byte[]) value, seed);
		}
		if (value instanceof CharSequence) {
			return hashBytes(value.toString().getBytes(StandardCharsets.UTF_8), seed);
		}
		final byte[] className = value.getClass().getName().getBytes(StandardCharsets.UTF_8);
		final long classHash = hashBytes(className, seed ^ 0xC2B2AE3D27D4EB4FL);
		return hashBytes(value.toString().getBytes(StandardCharsets.UTF_8), seed ^ classHash);
	}

	static long hashIdentifier(final Object identifier, final long seed) {
		return hashValue(identifier, seed ^ IDENTIFIER_SEED_XOR);
	}

	static long hashIdentifier(final long identifier, final long seed) {
		return hashLong(identifier, seed ^ IDENTIFIER_SEED_XOR);
	}

	static long hashLong(final long value, final long seed) {
		return MurmurHash3.hash(value, seed)[0];
	}

	static long hashDouble(final double value, final long seed) {
		return hashLong(Double.doubleToLongBits(value), seed);
	}

	static long rowHash(final long valueHash, final int row, final long seed) {
		final long[] key = { valueHash, row };
		return MurmurHash3.hash(key, 0, key.length, seed ^ ROW_SEED_XOR)[0];
	}

	static short seedHash(final long seed) {
		return (short) (MurmurHash3.hash(seed, 0L)[0] & 0xFFFFL);
	}

	static int indexFor(final long rowHash, final int lgWidth) {
		return (int) (rowHash & ((1L << lgWidth) - 1L));
	}

	private static long hashBytes(final byte[] data, final long seed) {
		return data.length == 0 ? hashLong(EMPTY_BYTES_TOKEN, seed) : MurmurHash3.hash(data, seed)[0];
	}
}
